public static Map<Node,Set<Node>> update(Map<Node,Set<Node>> groupByNode, Node vertex_u, Node vertex_v) {
    Set<Node> union = new HashSet<>();
    Set<Node> intersection = new HashSet<>();
    Set<Node> intersection2 = new HashSet<>();
    union.addAll(groupByNode.get(vertex_u));
    union.addAll(groupByNode.get(vertex_v));
    intersection.addAll(groupByNode.get(vertex_u));
    intersection.addAll(groupByNode.get(vertex_v));
    for (Node node : groupByNode.get(vertex_u)) {
        if (union.contains(node)) {
            groupByNode.get(node).addAll(groupByNode.get(vertex_v));
            intersection2.add(node);
        }
    }
    for (Node node : groupByNode.get(vertex_v)) {
        if (!intersection.contains(node)) {
            groupByNode.get(node).addAll(groupByNode.get(vertex_u));
            intersection2.add(node);
        }
    }
    for (Node node : intersection2) {
        groupByNode.get(node).remove(node);
    }
    return groupByNode;
}

