public static int[] findMinimumSpanningTree(Set<WeightedEdge> edges) {
    int[] parent = new int[edges.size()];
    int[] rank = new int[edges.size()];
    int mst_weight = 0;

    for (WeightedEdge edge : edges) {
        int u = edge.node1.id;
        int v = edge.node2.id;

        if (rank[u] > rank[v]) {
            parent[v] = u;
        } else if (rank[u] < rank[v]) {
            parent[u] = v;
        } else {
            parent[v] = u;
            rank[u] = rank[u] + 1;
        }
    }

    for (WeightedEdge edge : edges) {
        int u = edge.node1.id;
        int v = edge.node2.id;

        if (parent[u] != parent[v]) {
            mst_weight += edge.weight;
        }
    }

    return new int[] {mst_weight, parent};
}

